import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as n,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/magnet-transfer.md","filePath":"bn-BD/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"bn-BD/Other/magnet-transfer.md"};function p(c,a,h,m,u,g){return n(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer magnet link থেকে files download করে এবং আপনার নির্বাচিত cloud storage channel-এ automatically upload করে।</p><p>Anime episodes, videos, archives এবং similar files transfer করতে এটি useful। Magnet link paste করলে ImgBed background download task তৈরি করে। Download শেষ হলে file ImgBed-এ upload হয় এবং final link upload list-এ দেখা যায়।</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="কোথায়-ব্যবহার-করবেন" tabindex="-1">কোথায় ব্যবহার করবেন <a class="header-anchor" href="#কোথায়-ব্যবহার-করবেন" aria-label="Permalink to &quot;কোথায় ব্যবহার করবেন&quot;">​</a></h2><p>Magnet transfer entry homepage upload area-তে আছে।</p><p>Input box-এ magnet link paste করুন, <code>Transfer</code> নির্বাচন করুন, তারপর upload করুন।</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="প্রথমবার-ব্যবহারের-আগে" tabindex="-1">প্রথমবার ব্যবহারের আগে <a class="header-anchor" href="#প্রথমবার-ব্যবহারের-আগে" aria-label="Permalink to &quot;প্রথমবার ব্যবহারের আগে&quot;">​</a></h2><p>আগে admin panel-এ magnet transfer configure করুন।</p><p>সাধারণত দরকার:</p><ol><li>Download task চালানোর জন্য GitHub account।</li><li>Google Drive বা OneDrive-এর মতো cloud upload channel।</li><li>Target upload directory।</li><li>Task timeout।</li></ol><p>Settings ready হলে homepage-এ ফিরে magnet link paste করে transfer start করুন।</p><h2 id="magnet-link-upload-করা" tabindex="-1">Magnet Link Upload করা <a class="header-anchor" href="#magnet-link-upload-করা" aria-label="Permalink to &quot;Magnet Link Upload করা&quot;">​</a></h2><ol><li>Homepage upload box-এ magnet link paste করুন।</li><li>Mode <code>Transfer</code> সেট আছে কি না নিশ্চিত করুন।</li><li>Upload ক্লিক করুন।</li><li>ImgBed magnet task create করা পর্যন্ত অপেক্ষা করুন।</li><li>Task start হলে progress দেখতে bottom-right corner-এর <code>Magnet Tasks</code> floating panel ব্যবহার করুন।</li></ol><p>Download এবং upload সময় নিতে পারে। Speed magnet resource, GitHub runtime environment এবং selected cloud storage channel-এর ওপর depend করে।</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="completion-এর-পর" tabindex="-1">Completion-এর পর <a class="header-anchor" href="#completion-এর-পর" aria-label="Permalink to &quot;Completion-এর পর&quot;">​</a></h2><p>Task complete হলে upload list file name এবং link দেখায়।</p><p>Videos video preview দেখায়, images image preview দেখায়, আর other files regular file icon দেখায়।</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>আপনি copy করতে পারেন:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>Direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts বা notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>BBCode support করা forums</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>Bottom-right magnet task panel task count, task name, progress এবং final status দেখায়।</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>Task তৈরি হয়েছে এবং run হওয়ার অপেক্ষায়।</td></tr><tr><td>Downloading</td><td>Magnet resource download হচ্ছে।</td></tr><tr><td>Uploading</td><td>File download হয়েছে এবং cloud storage-এ upload হচ্ছে।</td></tr><tr><td>Completed</td><td>Upload successful এবং link copy করা যাবে।</td></tr><tr><td>Failed</td><td>Task successfully finish হয়নি। Message check করে আবার চেষ্টা করুন।</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Magnet link-এ multiple files থাকলে ImgBed display-এর জন্য main completed file prioritise করে।</li><li>Large files বেশি সময় নেয়। Task finish হওয়ার আগে page refresh না করাই ভালো।</li><li>Magnet resource-এ available peers না থাকলে download খুব slow বা fail হতে পারে।</li><li>Cloud account quota শেষ, authorization expired, বা upload directory ভুল হলে task fail করতে পারে।</li><li>Upload complete হওয়ার পর video preview আসতে কয়েক seconds লাগতে পারে।</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="magnet-link-paste-করার-পর-কিছু-start-হচ্ছে-না" tabindex="-1">Magnet Link paste করার পর কিছু start হচ্ছে না <a class="header-anchor" href="#magnet-link-paste-করার-পর-কিছু-start-হচ্ছে-না" aria-label="Permalink to &quot;Magnet Link paste করার পর কিছু start হচ্ছে না&quot;">​</a></h3><p>Admin panel-এ magnet transfer enabled আছে কি না এবং usable GitHub account ও cloud channel selected আছে কি না confirm করুন।</p><h3 id="download-সবসময়-slow" tabindex="-1">Download সবসময় slow <a class="header-anchor" href="#download-সবসময়-slow" aria-label="Permalink to &quot;Download সবসময় slow&quot;">​</a></h3><p>Magnet speed resource-এর ওপর depend করে। Available peers না থাকলে download খুব slow বা impossible হতে পারে।</p><h3 id="upload-এর-পর-preview-নেই" tabindex="-1">Upload-এর পর Preview নেই <a class="header-anchor" href="#upload-এর-পর-preview-নেই" aria-label="Permalink to &quot;Upload-এর পর Preview নেই&quot;">​</a></h3><p>আগে file link খোলে কি না confirm করুন। Video files browser-এ load হতে সামান্য সময় নিতে পারে, অথবা link direct খুলুন।</p><h3 id="task-fail-হলে-কী-check-করব" tabindex="-1">Task fail হলে কী check করব? <a class="header-anchor" href="#task-fail-হলে-কী-check-করব" aria-label="Permalink to &quot;Task fail হলে কী check করব?&quot;">​</a></h3><p>Magnet link valid কি না, cloud channel কাজ করছে কি না, এবং upload directory সঠিক কি না check করুন। তারপর task আবার submit করুন।</p>',38)])])}const w=i(s,[["render",p]]);export{b as __pageData,w as default};
